local LSdkZdTrack = LxClass("LSdkZdTrack", nil)

local LxBehaviour = LxRequire("LApp.component.LxBehaviour")

function LSdkZdTrack:LSdkZdTrack()
    ---@type LxBehaviour
    self._behaviour = LxBehaviour:New()

    ---国内有些打点不需要
    self._isInnerRegion = LGameSettings.platformRegion == LRegionConst.CHINA
end

function LSdkZdTrack:Dispose()
    if self._behaviour then
        self._behaviour:Dispose()
        self._behaviour = nil
    end
    table.removeall(self)
    self._isDispose = true
end

function LSdkZdTrack:Initialize()
    ---广告埋点
    self:RegTrackEvent()
end

