function LSdkZdTrack:RegTrackEvent()
    local eventReg = self._behaviour
    eventReg:AddEventHandler(EventNames.AFTER_WND_START, function(wndName)
        self:OnAfterWndStart(wndName)
    end)

    eventReg:AddEventHandler(EventNames.ON_WND_CLOSE, function(wndName)
        self:OnAfterWndClose(wndName)
    end)

    eventReg:AddEventHandler(EventNames.CLICK_BIND_BUTTON, function()
        self:SendTrackEvent(LSdkZdTrack.AF_BIND_FUN_CLICK)
    end)

    eventReg:AddEventHandler(EventNames.CLICK_RATING_STAR, function(star)
        self:OnClickRatingStar(star)
    end)

    eventReg:AddEventHandler(EventNames.CLICK_RATING_STORE, function(star)
        self:OnClickRatingStore(star)
    end)

    eventReg:AddEventHandler(EventNames.ON_CHARGE_MONEY_CHANGE, function(oldMoney, newMoney)
        oldMoney = oldMoney or 0
        newMoney = newMoney or 0
        if self._lastMoney and self._lastMoney ~= newMoney then
            self:SendTrackEvent(LSdkZdTrack.AF_SHIPMENT_SUCC)
        end
        if not self._lastMoney then
            self._lastMoney = newMoney
        end
    end)

    eventReg:AddEventHandler(EventNames.ON_MAIN_BATTLE_FINISHED, function(battleNode)
        self:OnMainBattleFinished(battleNode)
    end)

    eventReg:AddEventHandler(EventNames.ON_PLAYER_LEVEL_CHANGE, function(oldLevel, newLevel)
        self:OnPlayerLevelChange(oldLevel, newLevel)
    end)

    eventReg:AddEventHandler(EventNames.LOGIN_SCENE_START_LOAD, function()
        --self:SendTrackEvent(LSdkZdTrack.AF_LOADING)
    end)

    eventReg:AddEventHandler(EventNames.ENTER_UPDATE_SCENE, function()
        self:SendTrackEvent(LSdkZdTrack.AF_OPEN_GAME)
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_QUERY_START, function()
        self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_QUERY)
    end)

    eventReg:AddEventHandler(EventNames.LOGIN_UPDATE_REQ_OK, function()
        --self:SendTrackEvent(LSdkZdTrack.AF_END_QUERY)
    end)

    eventReg:AddEventHandler(EventNames.LOGIN_UPDATE_REQ_FAILURE, function()
        --self:SendTrackEvent(LSdkZdTrack.AF_FAIL_QUERY)
    end)

    eventReg:AddEventHandler(EventNames.QUERY_REMOTE_FIlE_START, function()
        self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_LOAD_CONFIG)
    end)

    eventReg:AddEventHandler(EventNames.QUERY_REMOTE_FIlE_RESULT, function(isOk)
        if isOk then
            self:SendTrackEvent(LSdkZdTrack.AF_END_LOAD_CONFIG)
        else
            self:SendTrackEvent(LSdkZdTrack.AF_FAIL_LOAD_CONFIG)
        end
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_NEED_HOT_RES, function(totalSize, isAuto)
        if not isAuto then
            self:SendTrackEvent(LSdkZdTrack.AF_LOADING_SCENE_SHOW)
        end
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_BEGIN_HOT_RES, function(totalSize, isAuto)
        if not isAuto then
            self:SendTrackEvent(LSdkZdTrack.AF_LOADING_SCENE_FINISH)
        end
        self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_UPDATA_SOURCE, "target_hotupdate_version", gLxServerList and gLxServerList.webResVer or "")
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_DOWNLOAD_RES_OK, function(...)
        self:SendTrackEvent(LSdkZdTrack.AF_END_UPDATA_SOURCE, "finish_hotupdate_version", gLxServerList and gLxServerList.webResVer or "")
    end)

    eventReg:AddEventHandler(EventNames.UPDATE_HOT_RES_FAILURE, function(...)
        self:SendTrackEvent(LSdkZdTrack.AF_FAIL_UPDATA_SOURCE)
    end)


    eventReg:AddEventHandler(EventNames.SDK_LOGIN_START, function(...)
        --self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_LOGIN)
        self:SendTrackEvent(LSdkZdTrack.AF_SDK_LOGIN_ACTIVATE)
    end)

    eventReg:AddEventHandler(EventNames.SDK_LOGIN_OK, function(...)
        --self:SendTrackEvent(LSdkZdTrack.AF_END_LOGIN)
    end)

    eventReg:AddEventHandler(EventNames.SDK_LOGIN_FAILURE, function(...)
        --self:SendTrackEvent(LSdkZdTrack.AF_END_LOGIN)
    end)


    eventReg:AddEventHandler(EventNames.CLICK_ENTER_GAME, function(...)
        --self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_GAME_BUTTON)
    end)

    eventReg:AddEventHandler(EventNames.FIRST_ENTER_CITY, function(...)
        if not self._isEnterCity then
            self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_GAME)
            self._isEnterCity = true
        end
    end)

    eventReg:AddEventHandler(EventNames.ON_START_CONNECT_SERVER, function(...)
        self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_CONNECT_SERVER)
    end)

    eventReg:AddEventHandler(EventNames.ON_END_CONNECT_SERVER, function(isOk)
        if isOk then
            self:SendTrackEvent(LSdkZdTrack.AF_END_CONNECT_SERVER)
        else
            self:SendTrackEvent(LSdkZdTrack.AF_FAIL_CONNECT_SERVER)
        end
    end)

    eventReg:AddEventHandler(EventNames.LOGIN_ACCOUNT_OK, function(battleNode)
        self:SendTrackEvent(LSdkZdTrack.AF_ROLE_LOGIN)
    end)

    eventReg:AddEventHandler(EventNames.NET_LOST, function(battleNode)
        self:SendTrackEvent(LSdkZdTrack.AF_NETWORK_FAIL)
    end)

    eventReg:AddEventHandler(EventNames.NET_RECONNECTED, function(battleNode)
        self:SendTrackEvent(LSdkZdTrack.AF_NETWORK_RECONNECT)
    end)


    eventReg:AddEventHandler(EventNames.ON_NEW_BIE_EVENT_START, function(eventId)
        --self:OnNewBieEventStart(eventId)
    end)

    -- eventReg:AddEventHandler(EventNames.ON_PLOT_EVENT_START, function(eventId)
    --     self:OnPlotEventStart(eventId)
    -- end)

    eventReg:AddEventHandler(EventNames.CREATE_ROLE_START, function()
        self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_CREATE_ROLE)
    end)

    eventReg:AddEventHandler(EventNames.CREATE_ROLE_FINISH, function(isOk)
        if isOk then
            local playerId = gModelPlayer and gModelPlayer:GetPlayerId() or ""
            local playerName = gModelPlayer and gModelPlayer:GetPlayerName() or ""
            self:SendTrackEvent(LSdkZdTrack.AF_END_CREATE_ROLE, "roleID", playerId,"roleName", playerName)

            --- 4.微小新增打点RegisterAccount传到卓动数据平台，打点方式和打点时机跟endcreaterole保持一致
            if self:IsWXGame() or self:IsDouYinGame() or self:IsBiliGame() then
                self:SendTrackEvent(LSdkZdTrack.AF_REGISTER_ACCOUNT,"roleID",playerId,"roleName",playerName)
            end
        else
            self:SendTrackEvent(LSdkZdTrack.AF_FAIL_CREATE_ROLE)
        end
    end)

    eventReg:AddEventHandler(EventNames.GET_BIND_REWARD, function(bindType)
        self:SendTrackEvent(LSdkZdTrack.AF_CLAIM_BUTTON_CLICK, "bindType", bindType)
    end)

    eventReg:AddEventHandler(EventNames.GET_BIND_REWARD_OK, function(bindType)
        self:SendTrackEvent(LSdkZdTrack.AF_CLAIMED_SHOW, "bindType", bindType)
    end)

    eventReg:AddEventHandler(EventNames.ON_COMMUNITY_LINK, function(fromType, fromUI, clickType)
        local ftype = ""
        if fromUI == "UILon" then
            ftype = "login"
        else
            ftype = "home"
        end

        ftype = ftype..tostring(clickType)
        local trackName
        if fromType == "show" then
            trackName = LSdkZdTrack.AF_COMMUNITY_SHOW
        elseif fromType == "click" then
            trackName = LSdkZdTrack.AF_COMMUNITY_CLICK
        elseif fromType == "link" then
            trackName = LSdkZdTrack.AF_COMMUNITY_LINK
        else
            return
        end
        self:SendTrackEvent(trackName, "community", ftype)
    end)

    eventReg:AddEventHandler(EventNames.ON_CALL_HERO_REWARD, function(...)
        --self:OnCallHeroReward(...)
    end)
    eventReg:AddEventHandler(EventNames.CLICK_SURVEY_ENTER, function(...)
        local surveyId = self:GetSurveyDataId()
        self:SendTrackEvent(LSdkZdTrack.CLICK_INSTANCE,"instance_id", surveyId)
    end)
    eventReg:AddEventHandler(EventNames.FINISH_SURVEY_RESULT, function(...)
        local surveyId = self:GetSurveyDataId()
        self:SendTrackEvent(LSdkZdTrack.FINISH_INSTANCE,"instance_id", surveyId)
    end)

    --------  绑定手机相关 start
    --- 点击绑定入口
    eventReg:AddEventHandler(EventNames.CLICK_PHONE_BIND_BTN,function()
        self:SendTrackEvent(LSdkZdTrack.MINIGAME_MPB_BTN)
    end)

    eventReg:AddEventHandler(EventNames.SDK_ACCOUNTBIND_RESULT,function(isOk,phone)
        if self:IsWXGame() and isOk and phone then
            local cgi = "yiyou_demon"
            local pn = "com.yiyou.demon.wxsmall"
            local uid = gLSdkImpl:CallMethod(LSdkMethod.GetSdkAccount) or ""
            self:SendTrackEvent(LSdkZdTrack.BIND_NUM_SUCCESS,"cgi",cgi,"pn",pn,"uid",uid,"account_num",phone)
        end
    end)
    --------  绑定手机相关 end

    --------  邀请好友相关 start
    ---@param invitecount number 邀请好友界面，点击前往按钮次数
    ---@param invited number 邀请好友界面，玩家已邀请的人数
    eventReg:AddEventHandler(EventNames.CLICK_INTIVE_FRIEND_BTN,function(invitecount,invited)
        if self:IsWXGame() then
            if invitecount and invited then
                self:SendTrackEvent(LSdkZdTrack.MINIGAME_INVITE_BTN,"invitecount",invitecount,"invited",invited)
            end
        end
    end)
    --------  邀请好友相关 end

    eventReg:AddEventHandler(EventNames.SUBSCRIBE_POP_SHOW,function(tplIds,types)
        if self:IsWXGame() then
            if tplIds and types then
                self:SendTrackEvent(LSdkZdTrack.SUBSCRIBE_TPL_POP_SHOW,"type",types,"tplId",tplIds)
            end
        end
    end)

    eventReg:AddEventHandler(EventNames.SUBSCRIBE_POP_ACCEPT,function(tplId,type)
        if self:IsWXGame() then
            if tplId and type then
                self:SendTrackEvent(LSdkZdTrack.SUBSCRIBE_TPL_ACCEPT,"type",type,"tplId",tplId)
            end
        end
    end)

    --- wx 实名打点 start
    eventReg:AddEventHandler(EventNames.TRACK_REAL_NAME,function(type,idCard,age,gender)
        if self:IsWXGame() then
            if type == 0 then
                self:SendTrackEvent(LSdkZdTrack.WXSMALL_REALNAME_SHOW)
            else
                self:SendTrackEvent(LSdkZdTrack.WXSMALL_REALNAME_SUCC,"idCard_base64",CS.Base64Encode(idCard),"age",age,"gender",gender)
            end
        end
    end)
    --- wx 实名打点 end
end

---@return boolean 是否有微信小程序
function LSdkZdTrack:IsWXGame()
    return CS.IsWebGL() and LWxHelper.IsWxPlatform()
end

function LSdkZdTrack:IsDouYinGame()
    return CS.IsWebGL() and LWxHelper.IsDouYinPlatform()
end

function LSdkZdTrack:IsBiliGame()
    return CS.IsWebGL() and LWxHelper.IsBiliPlatform()
end

function LSdkZdTrack:GetSurveyDataId()
    local surveyId
    local surveyData = gLSdkImpl:CallMethod(LSdkMethod.GetSurveyData)
    if surveyData then
        surveyId = surveyData.surveyId
    end
    return surveyId
end

function LSdkZdTrack:SendTrackEvent(eventName, ...)
    if LOG_INFO_ENABLED then
        printInfoN("trackEvent", eventName, ...)
    end
    gLSdkImpl:CallMethod(LSdkMethod.TrackEvent, eventName, ...)
end

function LSdkZdTrack:IsTrackRecorded(afName)
    local ids = gModelPlayer and gModelPlayer:GetFireOneTimeEventIds() or {}
    local id = LSdkZdTrack.AF_IDS[afName]
    if not id then return true end
    if ids[id] then
        return true
    else
        return false
    end
end


function LSdkZdTrack:RecordedTrack(afName)
    if not gModelPlayer then return end
    local id = LSdkZdTrack.AF_IDS[afName]
    if not id then return end
    gModelPlayer:OnFireOnetimeEventReq(id)
end


-----------------------------------
function LSdkZdTrack:OnPayOrderRequest(goodsId, productCp, price)
    if not self._isInnerRegion then
        self:SendTrackEvent(LSdkZdTrack.AF_RECHARGE_BUTTON_CLICK, "productID", productCp, "pointID", goodsId , "price", price)
    end
end

function LSdkZdTrack:OnBind(bindType)
    self:SendTrackEvent(LSdkZdTrack.AF_BIND_BUTTON_CLICK, "bindType", bindType)
    self:SendTrackEvent(LSdkZdTrack.AF_BIND_METHOD_GO, "bindType", bindType)
end

