function LSdkZdTrack:OnMainBattleFinished(battleNode)
    if not battleNode then return end

    if battleNode == 20010 then
        if not self:IsTrackRecorded(LSdkZdTrack.AF_finishGuide) then
            self:RecordedTrack(LSdkZdTrack.AF_finishGuide)
            local characterID = gModelPlayer:GetPlayerId() or 0
            local characterName = gModelPlayer:GetPlayerName() or ""
            local sRoleLevel = gModelPlayer:GetPlayerLv() or 0
        
            local serverID = gLGameLogin:GetServerId() or 0
            local serverName = gLGameLogin:GetServerName() or ""

            self:SendTrackEvent(LSdkZdTrack.AF_finishGuide, "characterID", characterID, "characterName", characterName, "serverID", serverID, "serverName", serverName)
        end
    end

    local ref = GameTable.MainInstanceMissionRef[battleNode]
    if not ref then return end
    local chapterId = ref.belongChapterId

    if not self._isInnerRegion then
        self:SendTrackEvent(LSdkZdTrack.AF_MAIN_STAGE_LEVEL, "stage", chapterId)

        local traceName = _MissionDataList[battleNode]
        if traceName then
            self:SendTrackEvent(traceName)
        end
    end
    

end

function LSdkZdTrack:OnPlayerLevelChange(oldLevel, newLevel)
    if not self._isInnerRegion then
        self:SendTrackEvent(LSdkZdTrack.AF_ROLE_LEVEL, "level", newLevel)
    end
end

local _newbieEventList = {
    [1064] = LSdkZdTrack.AF_DIALOGUE2,
    [1067] = LSdkZdTrack.AF_DIALOGUE3,

}
function LSdkZdTrack:OnNewBieEventStart(eventId)
    local traceName = _newbieEventList[eventId]
    if traceName then
        self:SendTrackEvent(traceName)
    end
end

local _plotEventList = {
    [1] = LSdkZdTrack.AF_DIALOGUE1,
    [10] = LSdkZdTrack.AF_DIALOGUE4,
    [11] = LSdkZdTrack.AF_DIALOGUE5,
    [21] = LSdkZdTrack.AF_DIALOGUE6,
    [22] = LSdkZdTrack.AF_DIALOGUE7,
    [23] = LSdkZdTrack.AF_DIALOGUE8,
    [700] = LSdkZdTrack.AF_NEW_TUTORIAL_COM,
}
function LSdkZdTrack:OnPlotEventStart(plotId)
    local traceName = _plotEventList[plotId]
    if traceName == LSdkZdTrack.AF_DIALOGUE1 then
        self:SendTrackEvent(LSdkZdTrack.AF_RegisterAccount)
        if not self._isEnterCity  then
            self:SendTrackEvent(LSdkZdTrack.AF_BEGIN_GAME)
            self._isEnterCity = true
        end
    end    
    if traceName ==  LSdkZdTrack.AF_NEW_TUTORIAL_COM then
        self:SendTrackEvent(traceName)
    end
end

function LSdkZdTrack:OnCallHeroReward(callNum, callRefId, itemList, fixedReward)
    local nameList = {
        [1001] = "nvshen" -- 高级召唤
    }
    local name = nameList[callRefId]
    if string.isempty(name) then return end
    local afName = LSdkZdTrack.AF_FIRST_RECRUIT
    if self:IsTrackRecorded(afName) then
        return
    end
    self:RecordedTrack(afName)
    self:SendTrackEvent(afName)
end

---@endregion  事件处理



return LSdkZdTrack